package com.uktc.schoolInventory.config;
import jakarta.servlet.http.HttpServletResponse;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.context.annotation.Bean;
import org.springframework.context.annotation.Configuration;
import org.springframework.security.authentication.AuthenticationManager;
import org.springframework.security.config.annotation.authentication.configuration.AuthenticationConfiguration;
import org.springframework.security.config.annotation.web.builders.HttpSecurity;
import org.springframework.security.config.annotation.web.configuration.EnableWebSecurity;
import org.springframework.security.core.session.SessionRegistry;
import org.springframework.security.core.session.SessionRegistryImpl;
import org.springframework.security.crypto.bcrypt.BCryptPasswordEncoder;
import org.springframework.security.crypto.password.PasswordEncoder;
import org.springframework.security.web.SecurityFilterChain;
import org.springframework.security.web.session.HttpSessionEventPublisher;
import static org.springframework.security.config.Customizer.withDefaults;
@Configuration
@EnableWebSecurity
public class SecurityConfig {
    @Autowired
    private CustomLoginSuccessHandler successHandler;
    @Autowired
    private SessionUserFilter sessionUserFilter;
    @Bean
    public SecurityFilterChain filterChain(HttpSecurity http) throws Exception {
        http
                .csrf(csrf -> csrf.disable())
                .authorizeHttpRequests(auth -> auth
                        .requestMatchers("/api/auth/register", "/api/auth/login").permitAll()
                        .anyRequest().authenticated()
                )
//                .httpBasic(withDefaults())

                .exceptionHandling(exception -> exception
                        .authenticationEntryPoint((request, response, authException) -> {
                            response.setStatus(HttpServletResponse.SC_UNAUTHORIZED);
                            response.getWriter().write("{\"error\": \"Unauthorized\"}");
                        })
                )


                .formLogin(form -> form

                        .loginProcessingUrl("/api/auth/login")

                        .successHandler(successHandler) // Слагаме нашия нов Handler тук
                        .permitAll()
                )
                .addFilterAfter(sessionUserFilter, org.springframework.security.web.authentication.UsernamePasswordAuthenticationFilter.class)
                .sessionManagement(session -> session
                        .maximumSessions(1)
                        .sessionRegistry(sessionRegistry())
                );
        return http.build();
    }
    @Bean
    public PasswordEncoder passwordEncoder(){
        return new BCryptPasswordEncoder();
    }
    @Bean
    public AuthenticationManager authenticationManager(AuthenticationConfiguration config) throws Exception{
        return config.getAuthenticationManager();
    }
    // Този Bean е задължителен за Baeldung метода!
    @Bean
    public HttpSessionEventPublisher httpSessionEventPublisher() {
        return new HttpSessionEventPublisher();
    }
    @Bean
    public SessionRegistry sessionRegistry() {
        return new SessionRegistryImpl();
    }
}

package com.uktc.schoolInventory.config;
import jakarta.servlet.http.HttpServletResponse;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.context.annotation.Bean;
import org.springframework.context.annotation.Configuration;
import org.springframework.security.authentication.AuthenticationManager;
import org.springframework.security.config.annotation.authentication.configuration.AuthenticationConfiguration;
import org.springframework.security.config.annotation.web.builders.HttpSecurity;
import org.springframework.security.config.annotation.web.configuration.EnableWebSecurity;
import org.springframework.security.core.session.SessionRegistry;
import org.springframework.security.core.session.SessionRegistryImpl;
import org.springframework.security.crypto.bcrypt.BCryptPasswordEncoder;
import org.springframework.security.crypto.password.PasswordEncoder;
import org.springframework.security.web.SecurityFilterChain;
import org.springframework.security.web.session.HttpSessionEventPublisher;
import org.springframework.security.web.context.HttpSessionSecurityContextRepository;
import org.springframework.security.web.context.SecurityContextRepository;
import static org.springframework.security.config.Customizer.withDefaults;
@Configuration
@EnableWebSecurity
public class SecurityConfig {
    @Autowired
    private SessionUserFilter sessionUserFilter;
    @Bean
    public SecurityFilterChain filterChain(HttpSecurity http) throws Exception {
        http
                .csrf(csrf -> csrf.disable())
                .authorizeHttpRequests(auth -> auth
                        .requestMatchers("/auth/register", "/auth/login").permitAll()
                        .anyRequest().authenticated()
                )

                .exceptionHandling(exception -> exception
                        .authenticationEntryPoint((request, response, authException) -> {
                            response.setStatus(HttpServletResponse.SC_UNAUTHORIZED);
                            response.getWriter().write("{\"error\": \"Unauthorized\"}");
                        })
                )

                .addFilterAfter(sessionUserFilter, org.springframework.security.web.authentication.UsernamePasswordAuthenticationFilter.class)
                .sessionManagement(session -> session
                        .maximumSessions(1)
                        .sessionRegistry(sessionRegistry())
                );
        return http.build();
    }
    @Bean
    public PasswordEncoder passwordEncoder(){
        return new BCryptPasswordEncoder();
    }
    @Bean
    public AuthenticationManager authenticationManager(AuthenticationConfiguration config) throws Exception{
        return config.getAuthenticationManager();
    }
    // Този Bean е задължителен за Baeldung метода!
    @Bean
    public HttpSessionEventPublisher httpSessionEventPublisher() {
        return new HttpSessionEventPublisher();
    }
    @Bean
    public SessionRegistry sessionRegistry() {
        return new SessionRegistryImpl();
    }
}

package com.uktc.schoolInventory.config;

import jakarta.servlet.FilterChain;
import jakarta.servlet.ServletException;
import jakarta.servlet.http.HttpServletRequest;
import jakarta.servlet.http.HttpServletResponse;
import org.springframework.security.core.Authentication;
import org.springframework.security.core.context.SecurityContextHolder;
import org.springframework.stereotype.Component;
import org.springframework.web.filter.OncePerRequestFilter;

import org.slf4j.Logger;
import org.slf4j.LoggerFactory;

import java.io.IOException;

@Component
public class SessionUserFilter extends OncePerRequestFilter {

    private static final Logger logger = LoggerFactory.getLogger(SessionUserFilter.class);

    @Override
    protected void doFilterInternal(HttpServletRequest request, HttpServletResponse response, FilterChain filterChain)
            throws ServletException, IOException {
        String path = request.getRequestURI();
        logger.info("SessionUserFilter: path={} sessionId={}", path, (request.getSession(false) != null ? request.getSession(false).getId() : "none"));
        // Allow unauthenticated access to login and register endpoints
        if (path.equals("/api/auth/register") || path.equals("/api/auth/login")) {
            logger.info("Allowing unauthenticated access to {}", path);
            filterChain.doFilter(request, response);
            return;
        }
        // Allow if authenticated by Spring Security
        Authentication authentication = SecurityContextHolder.getContext().getAuthentication();
        logger.info("Authentication: {}", authentication);
        if (authentication != null && authentication.isAuthenticated() && !"anonymousUser".equals(authentication.getPrincipal())) {
            logger.info("Allowing access for authenticated user: {}", authentication.getPrincipal());
            filterChain.doFilter(request, response);
            return;
        }
        logger.warn("Blocking request: not authenticated");
        // Otherwise, block
        response.sendError(HttpServletResponse.SC_UNAUTHORIZED, "No logged user in session");
    }
}

package com.uktc.schoolInventory.config;

import jakarta.servlet.FilterChain;
import jakarta.servlet.ServletException;
import jakarta.servlet.http.HttpServletRequest;
import jakarta.servlet.http.HttpServletResponse;
import jakarta.servlet.http.HttpSession;
import org.springframework.security.core.Authentication;
import org.springframework.security.core.context.SecurityContextHolder;
import org.springframework.stereotype.Component;
import org.springframework.web.filter.OncePerRequestFilter;

import org.slf4j.Logger;
import org.slf4j.LoggerFactory;

import java.io.IOException;

@Component
public class SessionUserFilter extends OncePerRequestFilter {

    private static final Logger logger = LoggerFactory.getLogger(SessionUserFilter.class);

    @Override
    protected void doFilterInternal(HttpServletRequest request, HttpServletResponse response, FilterChain filterChain)
            throws ServletException, IOException {
        String path = request.getRequestURI();
        logger.info("SessionUserFilter: path={} sessionId={}", path, (request.getSession(false) != null ? request.getSession(false).getId() : "none"));
        // Allow unauthenticated access to login and register endpoints
        if (path.equals("/auth/register") || path.equals("/auth/login")) {
            logger.info("Allowing unauthenticated access to {}", path);
            filterChain.doFilter(request, response);
            return;
        }
        // Allow if authenticated by Spring Security
        Authentication authentication = SecurityContextHolder.getContext().getAuthentication();
        logger.info("Authentication: {}", authentication);
        if (authentication != null && authentication.isAuthenticated() && !"anonymousUser".equals(authentication.getPrincipal())) {
            logger.info("Allowing access for authenticated user: {}", authentication.getPrincipal());
            filterChain.doFilter(request, response);
            return;
        }

        // Also check for manual session attributes set by AuthController
        HttpSession session = request.getSession(false);
        if (session != null) {
            String userEmail = (String) session.getAttribute("userEmail");
            if (userEmail != null) {
                logger.info("Allowing access for user with session attribute: {}", userEmail);
                filterChain.doFilter(request, response);
                return;
            }
        }

        logger.warn("Blocking request: not authenticated");
        // Otherwise, block
        response.sendError(HttpServletResponse.SC_UNAUTHORIZED, "No logged user in session");
    }
}

package com.uktc.schoolInventory.controllers;

import com.uktc.schoolInventory.dto.UserLoginDto;
import com.uktc.schoolInventory.dto.response.LoginResponse;
import com.uktc.schoolInventory.models.User;
import com.uktc.schoolInventory.services.AuthService;
import jakarta.servlet.http.HttpServletRequest;
import jakarta.servlet.http.HttpSession;
import org.springframework.http.ResponseEntity;
import org.springframework.security.authentication.UsernamePasswordAuthenticationToken;
import org.springframework.security.core.authority.SimpleGrantedAuthority;
import org.springframework.security.core.context.SecurityContextHolder;
import org.springframework.web.bind.annotation.PostMapping;
import org.springframework.web.bind.annotation.RequestBody;
import org.springframework.web.bind.annotation.RequestMapping;
import org.springframework.web.bind.annotation.RestController;

import java.util.List;

@RestController
@RequestMapping("/api/auth")
public class AuthController {
    private final AuthService authService;

    public AuthController(AuthService authService) {
        this.authService = authService;
    }

    @PostMapping("/login")
    public ResponseEntity<LoginResponse> login(@RequestBody UserLoginDto userLoginDto, HttpSession session, HttpServletRequest request){
        User authendicatedUser = authService.authenticate(userLoginDto);

        session.setAttribute("userId",authendicatedUser.getId());
        session.setAttribute("userEmail",authendicatedUser.getEmail());
        session.setAttribute("userIsAdmin",authendicatedUser.getIsAdmin());

        // Set Spring Security authentication in context and session
        UsernamePasswordAuthenticationToken authToken =
            new UsernamePasswordAuthenticationToken(
                authendicatedUser.getEmail(),
                authendicatedUser.getPasswordHash(), // Use password hash for principal
                List.of(new SimpleGrantedAuthority(authendicatedUser.getIsAdmin() ? "ROLE_ADMIN" : "ROLE_USER"))
            );
        authToken.setDetails(authendicatedUser); // Attach the full user object as details
        SecurityContextHolder.getContext().setAuthentication(authToken);
        session.setAttribute("SPRING_SECURITY_CONTEXT", SecurityContextHolder.getContext());

        LoginResponse loginResponse = new LoginResponse(
                authendicatedUser.getId(),
                authendicatedUser.getEmail(),
                authendicatedUser.getIsAdmin()
        );
        return ResponseEntity.ok(loginResponse);
    }
}

package com.uktc.schoolInventory.controllers;

import com.uktc.schoolInventory.dto.UserLoginDto;
import com.uktc.schoolInventory.dto.UserRegisterDto;
import com.uktc.schoolInventory.dto.response.LoginResponse;
import com.uktc.schoolInventory.models.User;
import com.uktc.schoolInventory.services.AuthService;
import jakarta.servlet.http.HttpServletRequest;
import jakarta.servlet.http.HttpSession;
import jakarta.validation.Valid;
import org.springframework.http.ResponseEntity;
import org.springframework.security.authentication.UsernamePasswordAuthenticationToken;
import org.springframework.security.core.authority.SimpleGrantedAuthority;
import org.springframework.security.core.context.SecurityContextHolder;
import org.springframework.web.bind.annotation.PostMapping;
import org.springframework.web.bind.annotation.RequestBody;
import org.springframework.web.bind.annotation.RequestMapping;
import org.springframework.web.bind.annotation.RestController;

import java.util.List;

@RestController
@RequestMapping("/api/auth")
public class AuthController {
    private final AuthService authService;

    public AuthController(AuthService authService) {
        this.authService = authService;
    }

    @PostMapping("/login")
    public ResponseEntity<LoginResponse> login(@Valid @RequestBody UserLoginDto userLoginDto, HttpSession session, HttpServletRequest request){
        User authendicatedUser = authService.authenticate(userLoginDto);

        session.setAttribute("userId",authendicatedUser.getId());
        session.setAttribute("userEmail",authendicatedUser.getEmail());
        session.setAttribute("userIsAdmin",authendicatedUser.getIsAdmin());

        // Set Spring Security authentication in context and session
        UsernamePasswordAuthenticationToken authToken =
            new UsernamePasswordAuthenticationToken(
                authendicatedUser.getEmail(),
                authendicatedUser.getPasswordHash(), // Use password hash for principal
                List.of(new SimpleGrantedAuthority(authendicatedUser.getIsAdmin() ? "ROLE_ADMIN" : "ROLE_USER"))
            );
        authToken.setDetails(authendicatedUser); // Attach the full user object as details
        SecurityContextHolder.getContext().setAuthentication(authToken);
        session.setAttribute("SPRING_SECURITY_CONTEXT", SecurityContextHolder.getContext());

        LoginResponse loginResponse = new LoginResponse(
                authendicatedUser.getId(),
                authendicatedUser.getEmail(),
                authendicatedUser.getIsAdmin()
        );
        return ResponseEntity.ok(loginResponse);
    }

    @PostMapping("/register")
    public ResponseEntity<?> register(@Valid @RequestBody UserRegisterDto userRegisterDto) {
        authService.register(userRegisterDto);
        return ResponseEntity.ok().build();
    }
}

package com.uktc.schoolInventory.controllers;

import com.uktc.schoolInventory.exception.ResourceNotFoundException;
import com.uktc.schoolInventory.exception.UnauthorizedActionException;
import com.uktc.schoolInventory.models.User;
import com.uktc.schoolInventory.repositories.UserRepository;
import org.springframework.web.bind.annotation.*;
import java.util.List;

@RestController
@RequestMapping("/api/users")
public class UserController {

    private final UserRepository userRepository;

    public UserController(UserRepository userRepository) {
        this.userRepository = userRepository;
    }

    @GetMapping
    public List<User> getAllUsers() {
        return userRepository.findAll();
    }

    @PostMapping
    public User createUser(@RequestBody User user) {
        return userRepository.save(user);
    }

    // Approve registration
    @PutMapping("/{id}/approve")
    public String approveUser(@PathVariable Long id, @RequestParam Long requesterId) {
        if (!requesterId.equals(1L)) {
            throw new UnauthorizedActionException("Only the Superuser can approve registrations");
        }
        User user = userRepository.findById(id)
                .orElseThrow(() -> new ResourceNotFoundException("User not found with id: " + id));
        return "User " + user.getFirstName() + " approved successfully.";
    }

    // Grant admin rights
    @PutMapping("/{id}/make-admin")
    public String makeAdmin(@PathVariable Long id, @RequestParam Long requesterId) {
        if (!requesterId.equals(1L)) {
            throw new UnauthorizedActionException("Only the Superuser can grant admin rights");
        }
        User user = userRepository.findById(id)
                .orElseThrow(() -> new ResourceNotFoundException("User not found with id: " + id));
        user.setIsAdmin(true);
        userRepository.save(user);
        return "User " + user.getFirstName() + " is now an administrator.";
    }

    // Delete user
    @DeleteMapping("/{id}")
    public String deleteUser(@PathVariable Long id, @RequestParam Long requesterId) {
        if (!requesterId.equals(1L)) {
            throw new UnauthorizedActionException("Only the Superuser can delete users");
        }
        if (!userRepository.existsById(id)) {
            throw new ResourceNotFoundException("User not found with id: " + id);
        }
        userRepository.deleteById(id);
        return "User with ID " + id + " deleted successfully.";
    }
}

